-- Update inventory_items from historical transactions
DO $$
DECLARE r RECORD;
BEGIN
  FOR r IN
    SELECT product_id, vendor_id, SUM(quantity) AS total_qty, MAX(created_at) AS ts
    FROM inventory_transactions
    WHERE notes = 'Historical import'
    GROUP BY product_id, vendor_id
  LOOP
    IF EXISTS (SELECT 1 FROM inventory_items WHERE product_id = r.product_id AND vendor_id = r.vendor_id) THEN
      UPDATE inventory_items SET quantity_on_hand = quantity_on_hand + r.total_qty, updated_at = r.ts
      WHERE product_id = r.product_id AND vendor_id = r.vendor_id;
    ELSE
      INSERT INTO inventory_items (product_id, vendor_id, quantity_on_hand, updated_at)
      VALUES (r.product_id, r.vendor_id, r.total_qty, r.ts);
    END IF;
  END LOOP;
END $$;

COMMIT;

